const body = $input.first().json.body;

if (!body.form_type || typeof body.form_type !== 'string' || body.form_type.trim() === '') {
  return [{ json: { valid: false, message: 'Missing or invalid form_type' } }];
}

if (!body.data || typeof body.data !== 'object' || Array.isArray(body.data)) {
  return [{ json: { valid: false, message: 'Missing or invalid data object' } }];
}

return [{ json: { valid: true, form_type: body.form_type.trim(), data: body.data } }];
